def chat(self, query: str, k: int = 5) -> Dict[str, Any]:
        """执行聊天

        Args:
            query: 用户查询
            k: 检索结果数量

        Returns:
            包含回答和来源的字典
        """
        try:
            # 执行RAG流程
            result = self.rag_backend.rag(query, k=k)

            # 添加到对话历史
            self.conversation_history.append({
                "role": "user",
                "content": query
            })
            self.conversation_history.append({
                "role": "assistant",
                "content": result["answer"]
            })

            return result
        except Exception as e:
            logger.error(f"Failed to chat: {e}")
            return {
                "answer": f"Error: {e}",
                "sources": []
            }

def clear_history(self):
        """清空对话历史"""
        self.conversation_history.clear()

def _create_client(self) -> OpenAI:
        """创建OpenAI客户端"""
        if self.llm_config.base_url:
            return OpenAI(
                base_url=self.llm_config.base_url,
                api_key=self.llm_config.api_key or "ollama"
            )
        else:
            return OpenAI(api_key=self.llm_config.api_key)

def retrieve(self, query: str, k: int = 5) -> List[Dict[str, Any]]:
        """检索相关文档"""
        try:
            results = self.chroma_storage.search_similar(query, n_results=k)
            self._sources = results
            return results
        except Exception as e:
            logger.error(f"Failed to retrieve documents: {e}")
            return []

def generate(self, query: str, context: List[Dict[str, Any]]) -> str:
        """生成回答"""
        # 构建上下文
        context_text = ""
        for i, item in enumerate(context):
            context_text += f"""## 参考资料 {i+1}

{item['document']}

"""

        # 构建提示词
        prompt = f"""请根据以下参考资料回答用户的问题。如果参考资料中没有相关信息，请基于你的知识回答，但要明确说明信息来源。

## 用户问题
{query}

## 参考资料
{context_text}

请生成详细、准确的回答，并在回答末尾列出使用的参考资料编号。
"""

        try:
            response = self.client.chat.completions.create(
                model=self.llm_config.model,
                messages=[
                    {
                        "role": "system",
                        "content": "你是一个专业的代码分析助手，擅长基于提供的代码和文档回答问题。"
                    },
                    {
                        "role": "user",
                        "content": prompt
                    }
                ],
                temperature=self.llm_config.temperature,
                max_tokens=self.llm_config.max_tokens
            )
            return response.choices[0].message.content
        except Exception as e:
            logger.error(f"Failed to generate response: {e}")
            return f"Error generating response: {e}"

def rag(self, query: str, k: int = 5) -> Dict[str, Any]:
        """执行RAG流程"""
        # 检索相关文档
        context = self.retrieve(query, k)

        # 生成回答
        answer = self.generate(query, context)

        return {
            "answer": answer,
            "sources": self._sources
        }

def get_sources(self) -> List[Dict[str, Any]]:
        """获取引用的来源"""
        return self._sources

def _find_entry_points(self) -> List[str]:
        """Find potential entry points"""
        entry_points = []
        common_entry_points = ["src/main.py", "main.py", "app.py", "run.py"]

        for entry_point in common_entry_points:
            if (self.project_path / entry_point).exists():
                entry_points.append(entry_point)

        return entry_points or ["src/main.py"]

def get_file_hash(file_path: Path) -> str:
    """Get file hash"""
    with open(file_path, 'rb') as f:
        content = f.read()
        return hashlib.md5(content).hexdigest()

def load_json(file_path: Path) -> Optional[Dict[str, Any]]:
    """Load JSON file"""
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            return json.load(f)
    except Exception:
        return None

def save_json(file_path: Path, data: Dict[str, Any]) -> bool:
    """Save JSON file"""
    try:
        file_path.parent.mkdir(exist_ok=True, parents=True)
        with open(file_path, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
        return True
    except Exception:
        return False

